      <VerticalTabsList>
        <VerticalTabsTrigger value="tab1">First Tab</VerticalTabsTrigger>
        <VerticalTabsTrigger value="tab2">Second Tab</VerticalTabsTrigger>
        <VerticalTabsTrigger value="tab3">Third Tab</VerticalTabsTrigger>
      </VerticalTabsList>
